export const getRootUrl = () => {




  return `/`
}

/**
 * @summary Root
 */
export const root = async ( options?: RequestInit): Promise<unknown> => {

  return customFetch<unknown>(getRootUrl(),
  {
    ...options,
    method: 'GET'


  }
);}





export const getRootQueryKey = () => {
    return [
    `/`
    ] as const;
    }


export const getRootQueryOptions = <TData = Awaited<ReturnType<typeof root>>, TError = ErrorType<unknown>>( options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof root>>, TError, TData>, request?: SecondParameter<typeof customFetch>}
) => {

const {query: queryOptions, request: requestOptions} = options ?? {};

  const queryKey =  queryOptions?.queryKey ?? getRootQueryKey();



    const queryFn: QueryFunction<Awaited<ReturnType<typeof root>>> = ({ signal }) => root({ signal, ...requestOptions });





   return  { queryKey, queryFn, ...queryOptions} as UseQueryOptions<Awaited<ReturnType<typeof root>>, TError, TData> & { queryKey: QueryKey }
}

export type RootQueryResult = NonNullable<Awaited<ReturnType<typeof root>>>
export type RootQueryError = ErrorType<unknown>


/**
 * @summary Root
 */

export function useRoot<TData = Awaited<ReturnType<typeof root>>, TError = ErrorType<unknown>>(
  options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof root>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getRootQueryOptions(options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







